"use client";

/**
 * PatientDetailsStep.tsx
 *
 * NowServing.ph pattern: one patient account can book for the whole family.
 * - "Booking for myself" ON  → auto-fill name/email/phone from logged-in user; all fields editable
 * - "Booking for myself" OFF → pick a saved family member (auto-fills name/age/gender from record)
 *   or add a new one via modal → saved to backend → refreshes dropdown; all fields remain editable
 *
 * The booker (logged-in user) always remains the `patient` FK on the
 * Appointment (for payment + notifications). The booked_for_* fields on
 * the Appointment carry the consultee's personal details.
 */

import { useEffect, useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { User, Phone, Mail, FileText, Users, Plus, Loader2 } from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group';
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from '@/components/ui/select';
import { Switch } from '@/components/ui/switch';
import { Button } from '@/components/ui/button';
import {
  Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter,
} from '@/components/ui/dialog';
import { useBookingStore } from '@/store/bookingStore';
import { useAuthStore } from '@/store';
import { api, API_ENDPOINTS } from '@/services/api';
import type { FamilyMember, FamilyMemberRelationship } from '@/types';

// ── Relationship label map ────────────────────────────────────────────────────
const RELATIONSHIP_LABELS: Record<string, string> = {
  spouse:  'Spouse',
  child:   'Child',
  parent:  'Parent',
  sibling: 'Sibling',
  other:   'Other',
};

// ── Add Family Member form state ──────────────────────────────────────────────
interface NewMemberForm {
  name: string;
  age: string;
  gender: 'male' | 'female' | 'other' | '';
  relationship: FamilyMemberRelationship | '';
}

const emptyForm: NewMemberForm = { name: '', age: '', gender: '', relationship: '' };

// ── Component ─────────────────────────────────────────────────────────────────

export default function PatientDetailsStep() {
  const { user } = useAuthStore();
  const queryClient = useQueryClient();

  const {
    patientDetails,
    isExistingPatient,
    setPatientDetails,
    setIsExistingPatient,
  } = useBookingStore();

  const [showAddModal, setShowAddModal] = useState(false);
  const [newMember, setNewMember] = useState<NewMemberForm>(emptyForm);
  const [formErrors, setFormErrors] = useState<Partial<NewMemberForm>>({});

  // ── Fetch saved family members from backend ───────────────────────────────
  const { data: familyMembers = [], isLoading: loadingMembers } = useQuery<FamilyMember[]>({
    queryKey: ['family-members'],
    queryFn: () => api.get<FamilyMember[]>(API_ENDPOINTS.FAMILY_MEMBERS),
    // Only fetch when the patient is booking for someone else
    enabled: !patientDetails.isForSelf,
  });

  // ── POST new family member ────────────────────────────────────────────────
  const addMemberMutation = useMutation({
    mutationFn: (payload: Omit<NewMemberForm, 'age'> & { age: number }) =>
      api.post<FamilyMember>(API_ENDPOINTS.FAMILY_MEMBERS, payload),
    onSuccess: (created) => {
      // Refresh the list and auto-select the newly created member
      queryClient.invalidateQueries({ queryKey: ['family-members'] });
      applyFamilyMember(created);
      setShowAddModal(false);
      setNewMember(emptyForm);
      setFormErrors({});
    },
  });

  // ── Pre-fill with logged-in user data when booking for self ───────────────
  useEffect(() => {
    if (patientDetails.isForSelf && user) {
      setPatientDetails({
        fullName:              user.name || '',
        email:                 user.email || '',
        contactNumber:         user.phone || '',
        bookedForRelationship: 'self',
        familyMemberId:        null,
      });
    }
  }, [patientDetails.isForSelf, user]);

  // ── Handlers ──────────────────────────────────────────────────────────────

  const handleInputChange = (field: string, value: string) => {
    setPatientDetails({ [field]: value });
  };

  const handleForSelfToggle = (isForSelf: boolean) => {
    setPatientDetails({
      isForSelf,
      bookedForRelationship: isForSelf ? 'self' : 'other',
      familyMemberId: null,
      ...(isForSelf
        ? {
            fullName:      user?.name || '',
            email:         user?.email || '',
            contactNumber: user?.phone || '',
            age:           '',
            gender:        '',
          }
        : {
            fullName:      '',
            email:         '',
            contactNumber: '',
            age:           '',
            gender:        '',
          }),
    });
  };

  /** Fill patient details form from a saved FamilyMember record. */
  const applyFamilyMember = (member: FamilyMember) => {
    setPatientDetails({
      fullName:              member.name,
      age:                   String(member.age),
      gender:                member.gender,
      familyMemberId:        member.id,
      bookedForRelationship: member.relationship,
    });
  };

  const handleFamilyMemberSelect = (value: string) => {
    if (value === '__add_new__') {
      setShowAddModal(true);
      return;
    }
    const member = familyMembers.find((m) => String(m.id) === value);
    if (member) applyFamilyMember(member);
  };

  // ── Add-member modal submit ───────────────────────────────────────────────

  const validateNewMember = (): boolean => {
    const errors: Partial<NewMemberForm> = {};
    if (!newMember.name.trim())    errors.name = 'Name is required.';
    if (!newMember.age.trim())     errors.age  = 'Age is required.';
    else if (isNaN(Number(newMember.age)) || Number(newMember.age) < 0)
      errors.age = 'Enter a valid age.';
    if (!newMember.gender)         errors.gender       = 'Gender is required.';
    if (!newMember.relationship)   errors.relationship = 'Relationship is required.';
    setFormErrors(errors);
    return Object.keys(errors).length === 0;
  };

  const handleAddMemberSubmit = () => {
    if (!validateNewMember()) return;
    addMemberMutation.mutate({
      name:         newMember.name.trim(),
      age:          Number(newMember.age),
      gender:       newMember.gender as 'male' | 'female' | 'other',
      relationship: newMember.relationship as FamilyMemberRelationship,
    });
  };

  // ── Render ────────────────────────────────────────────────────────────────

  return (
    <div className="space-y-6">

      {/* ── Patient Type ─────────────────────────────────────────────────── */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg flex items-center gap-2">
            <User className="h-5 w-5 text-primary" />
            Patient Type
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <RadioGroup
            value={isExistingPatient ? 'existing' : 'new'}
            onValueChange={(v) => setIsExistingPatient(v === 'existing')}
            className="flex gap-4"
          >
            <div className="flex items-center space-x-2">
              <RadioGroupItem value="new" id="new" />
              <Label htmlFor="new" className="cursor-pointer">New Patient</Label>
            </div>
            <div className="flex items-center space-x-2">
              <RadioGroupItem value="existing" id="existing" />
              <Label htmlFor="existing" className="cursor-pointer">Existing Patient</Label>
            </div>
          </RadioGroup>

          {/* Booking-for-self toggle */}
          <div className="flex items-center justify-between p-4 rounded-lg bg-secondary/50">
            <div className="flex items-center gap-2">
              <Users className="h-5 w-5 text-muted-foreground" />
              <span className="text-sm font-medium">Booking for myself</span>
            </div>
            <Switch
              checked={patientDetails.isForSelf}
              onCheckedChange={handleForSelfToggle}
            />
          </div>

          {/* Family member selector — shown when NOT booking for self */}
          {!patientDetails.isForSelf && (
            <div className="space-y-2">
              <Label>Select Family Member</Label>
              {loadingMembers ? (
                <div className="flex items-center gap-2 text-sm text-muted-foreground py-2">
                  <Loader2 className="h-4 w-4 animate-spin" />
                  Loading family members…
                </div>
              ) : (
                <Select
                  value={
                    patientDetails.familyMemberId
                      ? String(patientDetails.familyMemberId)
                      : undefined
                  }
                  onValueChange={handleFamilyMemberSelect}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Choose a family member" />
                  </SelectTrigger>
                  <SelectContent>
                    {familyMembers.map((m) => (
                      <SelectItem key={m.id} value={String(m.id)}>
                        {m.name} ({RELATIONSHIP_LABELS[m.relationship] ?? m.relationship})
                      </SelectItem>
                    ))}
                    {/* Always show "Add New" at the bottom */}
                    <SelectItem value="__add_new__">
                      <span className="flex items-center gap-1.5 text-primary font-medium">
                        <Plus className="h-3.5 w-3.5" />
                        Add New Family Member
                      </span>
                    </SelectItem>
                  </SelectContent>
                </Select>
              )}
            </div>
          )}
        </CardContent>
      </Card>

      {/* ── Patient Information Form ──────────────────────────────────────── */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg flex items-center gap-2">
            <FileText className="h-5 w-5 text-primary" />
            Patient Information
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid sm:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="fullName">
                Full Name <span className="text-destructive">*</span>
              </Label>
              <Input
                id="fullName"
                placeholder="Enter full name"
                value={patientDetails.fullName}
                onChange={(e) => handleInputChange('fullName', e.target.value)}
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="age">
                Age <span className="text-destructive">*</span>
              </Label>
              <Input
                id="age"
                type="number"
                placeholder="Enter age"
                value={patientDetails.age}
                onChange={(e) => handleInputChange('age', e.target.value)}
              />
            </div>
          </div>

          <div className="space-y-2">
            <Label>
              Gender <span className="text-destructive">*</span>
            </Label>
            <RadioGroup
              value={patientDetails.gender}
              onValueChange={(v) => handleInputChange('gender', v)}
              className="flex gap-4"
            >
              {(['male', 'female', 'other'] as const).map((g) => (
                <div key={g} className="flex items-center space-x-2">
                  <RadioGroupItem value={g} id={g} />
                  <Label htmlFor={g} className="cursor-pointer capitalize">{g}</Label>
                </div>
              ))}
            </RadioGroup>
          </div>

          <div className="grid sm:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="contactNumber">
                Contact Number <span className="text-destructive">*</span>
              </Label>
              <div className="relative">
                <Phone className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  id="contactNumber"
                  placeholder="+63 9XX XXX XXXX"
                  className="pl-10"
                  value={patientDetails.contactNumber}
                  onChange={(e) => handleInputChange('contactNumber', e.target.value)}
                />
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="email">
                Email Address <span className="text-destructive">*</span>
              </Label>
              <div className="relative">
                <Mail className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  id="email"
                  type="email"
                  placeholder="email@example.com"
                  className="pl-10"
                  value={patientDetails.email}
                  onChange={(e) => handleInputChange('email', e.target.value)}
                />
              </div>
            </div>
          </div>

          <div className="space-y-2">
            <Label htmlFor="symptoms">
              Reason for Consultation / Symptoms
            </Label>
            <Textarea
              id="symptoms"
              placeholder="Describe symptoms or reason for the consultation…"
              rows={4}
              value={patientDetails.symptoms}
              onChange={(e) => handleInputChange('symptoms', e.target.value)}
            />
            <p className="text-xs text-muted-foreground">
              This helps the doctor prepare for your consultation
            </p>
          </div>
        </CardContent>
      </Card>

      {/* Required fields notice */}
      <Card className="border-primary/30 bg-primary/5">
        <CardContent className="p-4">
          <div className="flex items-center gap-2 text-sm text-muted-foreground">
            <span className="text-destructive">*</span>
            <span>Required fields must be filled before continuing</span>
          </div>
        </CardContent>
      </Card>

      {/* ── Add Family Member Modal ───────────────────────────────────────── */}
      <Dialog open={showAddModal} onOpenChange={setShowAddModal}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Users className="h-5 w-5 text-primary" />
              Add Family Member
            </DialogTitle>
          </DialogHeader>

          <div className="space-y-4 py-2">
            {/* Name */}
            <div className="space-y-1.5">
              <Label htmlFor="fm-name">
                Full Name <span className="text-destructive">*</span>
              </Label>
              <Input
                id="fm-name"
                placeholder="e.g. Juan Santos Jr."
                value={newMember.name}
                onChange={(e) => setNewMember((p) => ({ ...p, name: e.target.value }))}
              />
              {formErrors.name && (
                <p className="text-xs text-destructive">{formErrors.name}</p>
              )}
            </div>

            {/* Age */}
            <div className="space-y-1.5">
              <Label htmlFor="fm-age">
                Age <span className="text-destructive">*</span>
              </Label>
              <Input
                id="fm-age"
                type="number"
                placeholder="e.g. 8"
                value={newMember.age}
                onChange={(e) => setNewMember((p) => ({ ...p, age: e.target.value }))}
              />
              {formErrors.age && (
                <p className="text-xs text-destructive">{formErrors.age}</p>
              )}
            </div>

            {/* Gender */}
            <div className="space-y-1.5">
              <Label>
                Gender <span className="text-destructive">*</span>
              </Label>
              <RadioGroup
                value={newMember.gender}
                onValueChange={(v) =>
                  setNewMember((p) => ({ ...p, gender: v as 'male' | 'female' | 'other' }))
                }
                className="flex gap-4"
              >
                {(['male', 'female', 'other'] as const).map((g) => (
                  <div key={g} className="flex items-center space-x-2">
                    <RadioGroupItem value={g} id={`fm-${g}`} />
                    <Label htmlFor={`fm-${g}`} className="cursor-pointer capitalize">{g}</Label>
                  </div>
                ))}
              </RadioGroup>
              {formErrors.gender && (
                <p className="text-xs text-destructive">{formErrors.gender}</p>
              )}
            </div>

            {/* Relationship */}
            <div className="space-y-1.5">
              <Label htmlFor="fm-relationship">
                Relationship <span className="text-destructive">*</span>
              </Label>
              <Select
                value={newMember.relationship}
                onValueChange={(v) =>
                  setNewMember((p) => ({ ...p, relationship: v as FamilyMemberRelationship }))
                }
              >
                <SelectTrigger id="fm-relationship">
                  <SelectValue placeholder="Select relationship" />
                </SelectTrigger>
                <SelectContent>
                  {Object.entries(RELATIONSHIP_LABELS).map(([val, label]) => (
                    <SelectItem key={val} value={val}>{label}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
              {formErrors.relationship && (
                <p className="text-xs text-destructive">{formErrors.relationship}</p>
              )}
            </div>
          </div>

          <DialogFooter className="gap-2">
            <Button
              variant="outline"
              onClick={() => { setShowAddModal(false); setNewMember(emptyForm); setFormErrors({}); }}
            >
              Cancel
            </Button>
            <Button
              className="gradient-primary border-0"
              onClick={handleAddMemberSubmit}
              disabled={addMemberMutation.isPending}
            >
              {addMemberMutation.isPending ? (
                <><Loader2 className="h-4 w-4 mr-2 animate-spin" />Saving…</>
              ) : (
                'Save Family Member'
              )}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}
